function monthly(){let mr=mrange(mon),ts=inRange(mr.start,mr.end),m=met(ts),pl=S.monthly[mon]||{focus:'',goals:['','',''],review:''};$('#app').innerHTML=`<section class="card"><div class="toolbar"><label>ماه<select id="monSel">${C.months.map((x,i)=>`<option value="${C.year}-${pad(i+1)}" ${mon.endsWith(pad(i+1))?'selected':''}>${x}</option>`).join('')}</select></label><button id="goMon" class="primary">نمایش</button></div><h3>${C.months[+mon.slice(5)-1]} ${fa(C.year)}</h3><div class="grid dash"><div class="c3">${kpi('تحقق ماه',m.comp+'٪',`${m.d} از ${m.tot}`,m.comp)}</div><div class="c3">${kpi('باقی‌مانده',m.todo,'فعالیت فعال',m.tot?m.todo/m.tot*100:0)}</div><div class="c3">${kpi('عقب‌افتاده',m.l,'نیازمند پیگیری',m.tot?m.l/m.tot*100:0)}</div><div class="c3">${kpi('میانگین پیشرفت',m.avg+'٪','بر اساس درصدها',m.avg)}</div></div></section><section class="card">${rowTitle('تمرکز و اهداف ماه','<button id="saveMon" class="primary">ذخیره ماه</button>')}<div class="two"><label>تمرکز ماه<textarea id="mf">${esc(pl.focus)}</textarea></label><div class="top3"><label>هدف ۱<input class="mg" value="${esc(pl.goals?.[0]||'')}"></label><label>هدف ۲<input class="mg" value="${esc(pl.goals?.[1]||'')}"></label><label>هدف ۳<input class="mg" value="${esc(pl.goals?.[2]||'')}"></label></div></div><label style="margin-top:12px">مرور پایان ماه<textarea id="mr">${esc(pl.review)}</textarea></label></section><section class="card">${rowTitle('تقویم ماهانه',`<button class="primary" onclick="openDlg(null,'${mr.start}')">+ افزودن فعالیت</button>`)}${monthGrid(mon)}</section><section class="card">${rowTitle('دسته‌بندی‌های ماه')}<canvas id="mcat" class="chart"></canvas></section>`;$('#goMon').onclick=()=>{mon=$('#monSel').value;sel=mon+'-01';render()};$('#saveMon').onclick=()=>{S.monthly[mon]={focus:$('#mf').value.trim(),goals:$$('.mg').map(x=>x.value.trim()),review:$('#mr').value.trim()};save();render()};bar($('#mcat'),group(ts,'category'))}
function monthGrid(k){let[y,m]=k.split('-').map(Number),off=(jToDate(fmt(y,m,1)).getDay()+1)%7,html=C.wd.map(w=>`<div class="mhead">${w}</div>`).join('')+'<div class="mcell" style="opacity:.25"></div>'.repeat(off);for(let d=1;d<=ml(y,m);d++){let dt=fmt(y,m,d),ts=dayTasks(dt);html+=`<div class="mcell ${dt===todayJ()?'today':''}" onclick="sel='${dt}';view='daily';$('#pageTitle').textContent='برنامه روزانه';buildNav();render()"><b>${fa(d)}</b><p class="muted">${ts.length?fa(ts.length)+' فعالیت':'—'}</p>${ts.slice(0,6).map(t=>`<span class="dot ${done(t)?'ok':late(t)?'late':''}"></span>`).join('')}</div>`}return`<div class="month">${html}</div>`}
function yearly(){let yr=yrange(),ts=inRange(yr.start,yr.end),m=met(ts),p=S.year;$('#app').innerHTML=`<section class="card"><h3>نمای کل سال ${fa(C.year)}</h3><div class="grid dash"><div class="c3">${kpi('تحقق سال',m.comp+'٪',`${m.d} از ${m.tot}`,m.comp)}</div><div class="c3">${kpi('انجام‌شده',m.d,'فعالیت تکمیل‌شده',m.tot?m.d/m.tot*100:0)}</div><div class="c3">${kpi('باقی‌مانده',m.todo,'فعالیت فعال',m.tot?m.todo/m.tot*100:0)}</div><div class="c3">${kpi('عقب‌افتاده',m.l,'نیازمند پیگیری',m.tot?m.l/m.tot*100:0)}</div></div></section><section class="card">${rowTitle('نقشه حرارتی عملکرد سال','<span class="muted">هر خانه یک روز</span>')}<div class="heat">${dates(yr.start,yr.end).map(d=>{let c=met(dayTasks(d)).comp,lv=c>=90?4:c>=65?3:c>=35?2:c>0?1:0;return`<span class="h${lv}" title="${d}: ${c}%"></span>`}).join('')}</div></section><section class="card">${rowTitle('ستون‌های راهبردی سال','<button id="saveYear" class="primary">ذخیره برنامه سالانه</button>')}<label>چشم‌انداز سال<textarea id="vision">${esc(p.vision)}</textarea></label><div class="tasks" id="pillars">${p.pillars.map(pi=>pillar(pi)).join('')}</div><button id="addPillar">+ ستون راهبردی جدید</button></section><section class="card">${rowTitle('عملکرد ۱۲ ماه')}<canvas id="ychart" class="chart"></canvas></section>`;$('#addPillar').onclick=()=>{S.year.pillars.push({id:id(),title:'',metric:'',target:'',progress:0,note:''});save();render()};$('#saveYear').onclick=saveYear;bar($('#ychart'),monthPerf())}function pillar(p){return`<div class="task" data-p="${p.id}"><div class="formGrid"><label>عنوان<input class="pt" value="${esc(p.title)}"></label><label>شاخص<input class="pm" value="${esc(p.metric)}"></label><label>هدف<input class="pg" value="${esc(p.target)}"></label><label>پیشرفت<input class="pp" type="number" min="0" max="100" value="${+p.progress||0}"></label><label class="wide">یادداشت<textarea class="pn">${esc(p.note||'')}</textarea></label></div><button class="danger" onclick="S.year.pillars=S.year.pillars.filter(x=>x.id!=='${p.id}');save();render()">حذف ستون</button></div>`}function saveYear(){S.year.vision=$('#vision').value.trim();S.year.pillars=$$('#pillars .task').map(c=>({id:c.dataset.p,title:c.querySelector('.pt').value.trim(),metric:c.querySelector('.pm').value.trim(),target:c.querySelector('.pg').value.trim(),progress:cl(+c.querySelector('.pp').value||0,0,100),note:c.querySelector('.pn').value.trim()})).filter(p=>p.title||p.metric||p.target||p.note);save();render()}
function tasksView(){let f=JSON.parse(sessionStorage.f||'{}'),q=f.q||'',st=f.st||'all',pr=f.pr||'all',ty=f.ty||'all',rows=[...S.tasks].sort(sortT);if(q)rows=rows.filter(t=>JSON.stringify(t).toLowerCase().includes(q.toLowerCase()));if(st!=='all')rows=rows.filter(t=>t.status===st);if(pr!=='all')rows=rows.filter(t=>t.priority===pr);if(ty!=='all')rows=rows.filter(t=>t.type===ty);$('#app').innerHTML=`<section class="card">${rowTitle('جست‌وجو، فیلتر و خروجی',`<button class="primary" onclick="openDlg(null,sel)">+ فعالیت جدید</button>`)}<div class="toolbar"><label>جست‌وجو<input id="fq" value="${esc(q)}"></label><label>وضعیت<select id="fst"><option value="all">همه</option>${C.status.map(x=>`<option ${st===x?'selected':''}>${x}</option>`).join('')}</select></label><label>اولویت<select id="fpr"><option value="all">همه</option>${C.prio.map(x=>`<option ${pr===x?'selected':''}>${x}</option>`).join('')}</select></label><label>نوع<select id="fty"><option value="all">همه</option>${C.types.map(x=>`<option ${ty===x?'selected':''}>${x}</option>`).join('')}</select></label><button id="apply" class="primary">اعمال</button><button id="backup">بکاپ JSON</button><label style="display:inline-flex;align-items:center" class="primary">بازیابی JSON<input id="import" type="file" accept="application/json" hidden></label></div><p class="muted">${fa(rows.length)} فعالیت از ${fa(S.tasks.length)} مورد نمایش داده شده است.</p></section><section class="card">${table(rows)}</section>`;$('#apply').onclick=()=>{sessionStorage.f=JSON.stringify({q:$('#fq').value.trim(),st:$('#fst').value,pr:$('#fpr').value,ty:$('#fty').value});render()};$('#backup').onclick=backup;$('#import').onchange=importBackup}
function taskList(ts){return ts.length?`<div class="tasks">${ts.map(task).join('')}</div>`:'<div class="empty">برای این بازه هنوز فعالیتی ثبت نشده است.</div>'}function task(t){let pc=t.priority==='بالا'?'high':t.priority==='متوسط'?'medium':'low';return`<article class="task ${done(t)?'done':''}"><div class="taskHead"><div><h4 style="margin:0 0 8px">${esc(t.title)}</h4><div class="badges"><span class="badge ${pc}">${esc(t.priority)}</span><span class="badge ${done(t)?'ok':late(t)?'late':''}">${esc(late(t)&&t.status!=='عقب‌افتاده'?'عقب‌افتاده':t.status)}</span><span class="badge">${esc(t.type)}</span><span class="badge">${fa(t.jDate)}</span>${t.start?`<span class="badge">${esc(t.start)}${t.end?' تا '+esc(t.end):''}</span>`:''}</div></div><button onclick="openDlg(S.tasks.find(x=>x.id==='${t.id}'))">ویرایش</button></div>${t.desc?`<p class="muted">${esc(t.desc)}</p>`:''}<div class="bar"><i style="width:${cl(+t.progress||0,0,100)}%"></i></div><span class="muted">پیشرفت: ${fa(t.progress||0)}٪</span><div><button onclick="patch('${t.id}',{progress:100,status:'انجام‌شده'})">انجام شد</button> <button onclick="patch('${t.id}',{status:'در حال انجام',progress:Math.max(10,+(S.tasks.find(x=>x.id==='${t.id}')?.progress||0))})">در حال انجام</button> <button onclick="patch('${t.id}',{status:'عقب‌افتاده'})">عقب‌افتاده</button></div></article>`}function table(rows){if(!rows.length)return'<div class="empty">فعالیتی با این فیلترها پیدا نشد.</div>';return`<div class="tableWrap"><table><thead><tr><th>تاریخ</th><th>عنوان</th><th>زمان</th><th>نوع</th><th>دسته</th><th>اولویت</th><th>وضعیت</th><th>پیشرفت</th><th>عملیات</th></tr></thead><tbody>${rows.map(t=>`<tr><td>${fa(t.jDate)}</td><td><b>${esc(t.title)}</b><br><span class="muted">${esc(t.desc||'')}</span></td><td>${esc([t.start,t.end].filter(Boolean).join(' تا ')||'—')}</td><td>${esc(t.type)}</td><td>${esc(t.category||'')}</td><td>${esc(t.priority)}</td><td>${esc(t.status)}</td><td>${fa(t.progress||0)}٪</td><td><button onclick="openDlg(S.tasks.find(x=>x.id==='${t.id}'))">ویرایش</button></td></tr>`).join('')}</tbody></table></div>`}
function openDlg(t=null,d=sel){edit=t?.id||null;$('#dlgTitle').textContent=t?'ویرایش فعالیت':'ثبت فعالیت جدید';$('#delBtn').classList.toggle('hide',!t);$('#id').value=t?.id||'';$('#title').value=t?.title||'';$('#desc').value=t?.desc||'';$('#jdate').value=t?.jDate||d;$('#start').value=t?.start||'';$('#end').value=t?.end||'';$('#type').value=t?.type||'کار';$('#priority').value=t?.priority||'متوسط';$('#status').value=t?.status||'انجام‌نشده';$('#category').value=t?.category||'';$('#repeat').value=t?.repeat||'none';$('#reminder').value=t?.reminder||'off';$('#progress').value=+(t?.progress||0);$('#pval').textContent=fa($('#progress').value)+'٪';$('#notes').value=t?.notes||'';$('#cats').innerHTML=[...new Set(S.tasks.map(x=>x.category).filter(Boolean))].map(x=>`<option value="${esc(x)}">`).join('');$('#taskDialog').showModal()}function closeDlg(){$('#taskDialog').close();edit=null}function saveTask(){let jd=jDate($('#jdate').value);if(!jd)return alert('تاریخ باید در سال ۱۴۰۵ و با فرمت 1405-04-03 باشد.');let now=new Date().toISOString(),old=S.tasks.find(x=>x.id===edit),t={id:edit||id(),title:$('#title').value.trim(),desc:$('#desc').value.trim(),jDate:jd,start:$('#start').value,end:$('#end').value,type:$('#type').value,priority:$('#priority').value,status:$('#status').value,category:$('#category').value.trim()||$('#type').value,repeat:$('#repeat').value,reminder:$('#reminder').value,notes:$('#notes').value.trim(),progress:+$('#progress').value||0,parent:old?.parent||null,createdAt:old?.createdAt||now,updatedAt:now};if(!t.title)return;let i=S.tasks.findIndex(x=>x.id===t.id);i>=0?S.tasks[i]=t:S.tasks.push(t);if(!edit&&t.repeat!=='none')makeRepeat(t);sel=jd;mon=jd.slice(0,7);wstart=week(jd).start;save();closeDlg();render()}function makeRepeat(t){let cur=t.jDate,out=[];while(true){if(t.repeat==='daily')cur=addDays(cur,1);else if(t.repeat==='weekly')cur=addDays(cur,7);else if(t.repeat==='monthly'){let p=par(cur),nm=p.jm===12?1:p.jm+1,ny=p.jm===12?p.jy+1:p.jy;cur=fmt(ny,nm,Math.min(p.jd,ml(ny,nm)))}else break;if(cur>yrange().end||!cur.startsWith(String(C.year)))break;out.push({...t,id:id(),jDate:cur,parent:t.id,repeat:'none',status:'انجام‌نشده',progress:0});if(out.length>370)break}S.tasks.push(...out)}function patch(tid,obj){let t=S.tasks.find(x=>x.id===tid);if(!t)return;Object.assign(t,obj,{updatedAt:new Date().toISOString()});save();render()}
function monthPerf(){let o={};for(let i=1;i<=12;i++){let k=`${C.year}-${pad(i)}`,r=mrange(k);o[C.months[i-1]]=met(inRange(r.start,r.end)).comp}return o}function setup(c){let r=devicePixelRatio||1,b=c.getBoundingClientRect();c.width=Math.max(320,b.width)*r;c.height=Math.max(180,b.height)*r;let x=c.getContext('2d');x.setTransform(r,0,0,r,0,0);x.clearRect(0,0,b.width,b.height);x.fillStyle='#fbfefb';x.fillRect(0,0,b.width,b.height);return[x,b.width,b.height]}function nodata(x,w,h){x.fillStyle='#657468';x.font='14px Tahoma';x.textAlign='center';x.fillText('هنوز داده‌ای برای نمایش وجود ندارد',w/2,h/2)}function bar(c,o){let e=(Array.isArray(o)?o.map(p=>[p.label,p.value]):Object.entries(o)).filter(x=>+x[1]>=0).slice(0,14),[x,w,h]=setup(c);if(!e.length||e.every(a=>+a[1]===0))return nodata(x,w,h);let mx=Math.max(1,...e.map(a=>+a[1])),pad=36,ch=h-70,cw=w-pad*2,g=8,bw=Math.max(12,(cw-g*(e.length-1))/e.length);x.strokeStyle='#dce8dc';for(let i=0;i<5;i++){let y=pad+ch-ch/4*i;x.beginPath();x.moveTo(pad,y);x.lineTo(w-pad,y);x.stroke()}e.forEach((a,i)=>{let bh=+a[1]/mx*ch,xx=pad+i*(bw+g),yy=pad+ch-bh,gr=x.createLinearGradient(0,yy,0,pad+ch);gr.addColorStop(0,'#2f7a43');gr.addColorStop(1,'#aee0b3');x.fillStyle=gr;x.beginPath();x.roundRect(xx,yy,bw,bh,8);x.fill();x.fillStyle='#657468';x.font='11px Tahoma';x.textAlign='center';x.fillText(fa(a[0]).slice(0,8),xx+bw/2,h-20);x.fillStyle='#15231a';x.font='700 11px Tahoma';x.fillText(fa(a[1]),xx+bw/2,yy-6)})}function line(c,pts){let[x,w,h]=setup(c),e=pts;if(!e.length)return nodata(x,w,h);let pad=38,ch=h-68,cw=w-pad*2;x.strokeStyle='#dce8dc';for(let i=0;i<5;i++){let y=pad+ch-ch/4*i;x.beginPath();x.moveTo(pad,y);x.lineTo(w-pad,y);x.stroke()}x.beginPath();e.forEach((p,i)=>{let xx=pad+(e.length===1?cw/2:cw/(e.length-1)*i),yy=pad+ch-(+p.value/100)*ch;i?x.lineTo(xx,yy):x.moveTo(xx,yy)});x.strokeStyle='#2f7a43';x.lineWidth=3;x.stroke();e.forEach((p,i)=>{let xx=pad+(e.length===1?cw/2:cw/(e.length-1)*i),yy=pad+ch-(+p.value/100)*ch;x.fillStyle='#fff';x.beginPath();x.arc(xx,yy,5,0,Math.PI*2);x.fill();x.stroke();x.fillStyle='#657468';x.font='11px Tahoma';x.textAlign='center';if(i%Math.ceil(e.length/7)===0)x.fillText(fa(p.label),xx,h-20)})}function dough(c,o){let e=Object.entries(o).filter(a=>+a[1]>0),[x,w,h]=setup(c);if(!e.length)return nodata(x,w,h);let total=e.reduce((s,a)=>s+ +a[1],0),cols=['#74b47b','#aad8ae','#2f7a43','#dcefdc','#e7a83d','#88b99a'],cx=w*.35,cy=h*.52,r=Math.min(w,h)*.28,st=-Math.PI/2;e.forEach((a,i)=>{let an=+a[1]/total*Math.PI*2;x.beginPath();x.moveTo(cx,cy);x.arc(cx,cy,r,st,st+an);x.closePath();x.fillStyle=cols[i%cols.length];x.fill();st+=an});x.globalCompositeOperation='destination-out';x.beginPath();x.arc(cx,cy,r*.58,0,Math.PI*2);x.fill();x.globalCompositeOperation='source-over';x.fillStyle='#15231a';x.font='700 18px Tahoma';x.textAlign='center';x.fillText(fa(total),cx,cy+6);x.textAlign='right';x.font='12px Tahoma';e.forEach((a,i)=>{let y=38+i*27;x.fillStyle=cols[i%cols.length];x.fillRect(w-24,y-10,12,12);x.fillStyle='#15231a';x.fillText(`${a[0]}: ${fa(a[1])}`,w-32,y)})}
function reminders(){let now=new Date(),tj=todayJ(),up=S.tasks.filter(t=>{if(!t.start||t.reminder==='off'||done(t)||canc(t)||t.jDate!==tj)return false;let[h,m]=t.start.split(':').map(Number),d=new Date(now.getFullYear(),now.getMonth(),now.getDate(),h,m);d.setMinutes(d.getMinutes()-(+t.reminder||0));let diff=d-now;return diff<=30*60000&&diff>=-20*60000}),la=S.tasks.filter(late).slice(0,3),r=$('#reminders');if(!up.length&&!la.length){r.classList.add('hide');return}r.classList.remove('hide');r.innerHTML=[up.length?'یادآور: '+up.map(t=>esc(t.title)).join('، '):'',la.length?'عقب‌افتاده: '+la.map(t=>esc(t.title)).join('، '):''].filter(Boolean).join(' · ')}function printPDF(){let yr=yrange(),tj=todayJ(),wr=week(tj),mr=mrange(tj.slice(0,7)),secs=[['امروز',dayTasks(tj)],['این هفته',inRange(wr.start,wr.end)],['این ماه',inRange(mr.start,mr.end)],['سال ۱۴۰۵',inRange(yr.start,yr.end)]];$('#printArea').innerHTML=`<h1>گزارش پلنر حرفه‌ای ۱۴۰۵</h1><p>تاریخ گزارش: ${showDate(tj)}</p>${secs.map(s=>{let m=met(s[1]);return`<div class="printCard"><h2>${s[0]}</h2><p>تحقق: ${fa(m.comp)}٪ | انجام‌شده: ${fa(m.d)} | باقی‌مانده: ${fa(m.todo)} | عقب‌افتاده: ${fa(m.l)}</p>${table(s[1]).replace(/<button[\s\S]*?<\/button>/g,'')}</div>`}).join('')}`;window.print()}function backup(){let blob=new Blob([JSON.stringify(S,null,2)],{type:'application/json'}),u=URL.createObjectURL(blob),a=document.createElement('a');a.href=u;a.download='planner-1405-backup.json';a.click();URL.revokeObjectURL(u)}function importBackup(e){let f=e.target.files[0];if(!f)return;let rd=new FileReader();rd.onload=()=>{try{let j=JSON.parse(rd.result);if(!Array.isArray(j.tasks))throw Error();if(confirm('اطلاعات فعلی جایگزین شود؟')){S=Object.assign(seed(),j);save();render()}}catch{alert('فایل معتبر نیست')}};rd.readAsText(f)}
window.openDlg=openDlg;window.patch=patch;window.S=S;window.save=save;window.render=render;window.addDays=addDays;Object.defineProperty(window,'sel',{get:()=>sel,set:v=>sel=v});Object.defineProperty(window,'view',{get:()=>view,set:v=>view=v});Object.defineProperty(window,'mon',{get:()=>mon,set:v=>mon=v});Object.defineProperty(window,'wstart',{get:()=>wstart,set:v=>wstart=v});



