C.nav=[['dashboard','📊','داشبورد','داشبورد مدیریتی'],['inbox','📥','Inbox','ورودی‌ها / Inbox'],['daily','☀️','روزانه','برنامه روزانه'],['weekly','🗓️','هفتگی','برنامه هفتگی'],['monthly','📅','ماهانه','برنامه ماهانه'],['goals','🏆','اهداف','اهداف و حاشیه برتری'],['habits','🟩','عادت‌ها','Habit Tracker'],['yearly','🎯','سالانه','برنامه سالانه'],['tasks','✅','کارها','مدیریت کارها و جست‌وجو']];
function seed(){return{tasks:[],daily:{},weekly:{},monthly:{},inbox:[],habits:{items:[],checks:{}},goals:{yearly:[],seasonal:[],monthly:[],edge:[]},year:{vision:'سال ۱۴۰۵؛ تمرکز، نظم، پیشرفت پایدار و خروجی‌های قابل اندازه‌گیری.',pillars:[{id:id(),title:'رشد علمی و پایان‌نامه',metric:'خروجی علمی/تحلیلی',target:'۱۲ خروجی مهم',progress:0,note:''},{id:id(),title:'کار سازمانی و HSE',metric:'اقدام‌های تکمیل‌شده',target:'پیگیری منظم',progress:0,note:''},{id:id(),title:'سلامت و انرژی',metric:'روزهای ورزش',target:'۳ روز در هفته',progress:0,note:''},{id:id(),title:'تولید محتوا و برند شخصی',metric:'محتوای منتشرشده',target:'انتشار پایدار',progress:0,note:''}]}}}
function migratePlannerV4(){let d=seed();S.tasks=Array.isArray(S.tasks)?S.tasks:[];S.daily=S.daily||{};S.weekly=S.weekly||{};S.monthly=S.monthly||{};S.inbox=Array.isArray(S.inbox)?S.inbox:[];S.habits=S.habits||d.habits;S.habits.items=Array.isArray(S.habits.items)?S.habits.items:[];S.habits.checks=S.habits.checks||{};S.goals=S.goals||d.goals;['yearly','seasonal','monthly','edge'].forEach(k=>{S.goals[k]=Array.isArray(S.goals[k])?S.goals[k]:[];S.goals[k].forEach(g=>{g.id=g.id||id();g.steps=Array.isArray(g.steps)?g.steps:[];g.steps.forEach(s=>s.id=s.id||id())})});S.year=S.year||d.year;S.year.pillars=Array.isArray(S.year.pillars)?S.year.pillars:d.year.pillars;localStorage.setItem(K,JSON.stringify(S))}
function render(){window.addDays=addDays;$('#todayText').textContent='امروز: '+showDate(todayJ());reminders();if(view==='dashboard')dash();else if(view==='inbox')inboxView();else if(view==='daily')daily();else if(view==='weekly')weekly();else if(view==='monthly')monthly();else if(view==='goals')goalsView();else if(view==='habits')habitsView();else if(view==='yearly')yearly();else tasksView()}
function dash(){let td=dayTasks(todayJ()),wr=week(todayJ()),mr=mrange(todayJ().slice(0,7)),yr=yrange(),wt=inRange(wr.start,wr.end),mt=inRange(mr.start,mr.end),yt=inRange(yr.start,yr.end),tm=met(td),wm=met(wt),mm=met(mt),ym=met(yt),meet=td.filter(t=>t.type==='قرار ملاقات');$('#app').innerHTML=`<div class="grid dash"><div class="c3">${kpi('تحقق امروز',tm.comp+'٪',`${tm.d} از ${tm.tot}`,tm.comp)}</div><div class="c3">${kpi('تحقق هفته',wm.comp+'٪',`${wm.d} از ${wm.tot}`,wm.comp)}</div><div class="c3">${kpi('تحقق ماه',mm.comp+'٪',`${mm.d} از ${mm.tot}`,mm.comp)}</div><div class="c3">${kpi('تحقق سال',ym.comp+'٪',`${ym.d} از ${ym.tot}`,ym.comp)}</div><div class="c3">${kpi('Inbox',S.inbox.length,'ورودی‌های پردازش‌نشده',Math.min(100,S.inbox.length*10))}</div><div class="c3">${kpi('انجام‌شده',ym.d,'کل سال',100)}</div><div class="c3">${kpi('باقی‌مانده',ym.todo,'فعالیت فعال',ym.tot?ym.todo/ym.tot*100:0)}</div><div class="c3">${kpi('عقب‌افتاده',ym.l,'نیازمند پیگیری',ym.tot?ym.l/ym.tot*100:0)}</div><section class="card c6">${rowTitle('روند عملکرد روزانه','<span class="muted">۱۴ روز اخیر</span>')}<canvas id="trend" class="chart"></canvas></section><section class="card c6">${rowTitle('نمودار عملکرد هفتگی','<span class="muted">۸ هفته اخیر</span>')}<canvas id="weekPerfChart" class="chart"></canvas></section><section class="card c6">${rowTitle('نمودار عملکرد ماهیانه','<span class="muted">۱۲ ماه ۱۴۰۵</span>')}<canvas id="monthChart" class="chart"></canvas></section><section class="card c6">${rowTitle('نمودار عملکرد سالیانه','<span class="muted">چهار فصل</span>')}<canvas id="yearPerfChart" class="chart"></canvas></section><section class="card c5">${rowTitle('کارها بر اساس اولویت')}<canvas id="prioChart" class="chart"></canvas></section><section class="card c7">${rowTitle('کارها بر اساس دسته‌بندی')}<canvas id="catChart" class="chart"></canvas></section><section class="card c12">${rowTitle('فعالیت‌های امروز',`<button class="primary" onclick="openDlg(null,'${todayJ()}')">+ افزودن امروز</button>`)}${taskList(td)}</section></div>`;line($('#trend'),Array.from({length:14},(_,i)=>{let d=addDays(todayJ(),i-13),p=par(d);return{label:fa(p.jd),value:met(dayTasks(d)).comp}}));bar($('#weekPerfChart'),weekPerf());bar($('#monthChart'),monthPerf());bar($('#yearPerfChart'),quarterPerf());dough($('#prioChart'),group(yt,'priority'));bar($('#catChart'),group(yt,'category'))}
function inboxView(){let items=S.inbox||[];$('#app').innerHTML=`<section class="card">${rowTitle('Inbox / ورودی‌ها','<span class="muted">ایده‌ها و کارهای خام قبل از زمان‌بندی</span>')}<div class="inboxAdd"><label>عنوان ورودی<input id="inboxTitle" placeholder="مثلاً: پیگیری گزارش ماهانه"></label><label>اولویت<select id="inboxPr"><option>متوسط</option><option>بالا</option><option>پایین</option></select></label><label class="wide">توضیح کوتاه<textarea id="inboxNote" placeholder="هر چیزی که سریع می‌خواهی ثبت کنی..."></textarea></label><button id="addInbox" class="primary">+ افزودن به Inbox</button></div></section><section class="card">${rowTitle('لیست ورودی‌ها',`<span class="muted">${fa(items.length)} مورد</span>`)}${items.length?`<div class="tasks">${items.map(inboxCard).join('')}</div>`:'<div class="empty">Inbox خالی است. هر فکر، کار یا ایده خام را سریع اینجا بریز و بعداً زمان‌بندی کن.</div>'}</section>`;$('#addInbox').onclick=()=>{let title=$('#inboxTitle').value.trim();if(!title)return alert('عنوان ورودی را وارد کن.');S.inbox.unshift({id:id(),title,note:$('#inboxNote').value.trim(),priority:$('#inboxPr').value,createdAt:new Date().toISOString(),status:'باز'});save();render()}}
function inboxCard(it){let pc=it.priority==='بالا'?'high':it.priority==='متوسط'?'medium':'low';return`<article class="task"><div class="taskHead"><div><h4 style="margin:0 0 8px">${esc(it.title)}</h4><div class="badges"><span class="badge ${pc}">${esc(it.priority||'متوسط')}</span><span class="badge">Inbox</span><span class="badge">${fa((it.createdAt||'').slice(0,10))}</span></div></div><div><button onclick="inboxToTask('${it.id}')">زمان‌بندی</button> <button class="danger" onclick="delInbox('${it.id}')">حذف</button></div></div>${it.note?`<p class="muted">${esc(it.note)}</p>`:''}</article>`}
function delInbox(i){S.inbox=S.inbox.filter(x=>x.id!==i);save();render()}function inboxToTask(i){let it=S.inbox.find(x=>x.id===i);if(!it)return;openDlg(null,sel);$('#title').value=it.title||'';$('#desc').value=it.note||'';$('#priority').value=it.priority||'متوسط';$('#category').value='Inbox'}
function daily(){let p=S.daily[sel]||{focus:'',top3:['','','']},ts=dayTasks(sel),m=met(ts);$('#app').innerHTML=`<section class="card"><div class="toolbar"><label>انتخاب روز<input id="dayInp" value="${sel}"></label><button id="goDay" class="primary">نمایش</button><button onclick="sel='${todayJ()}';render()">امروز</button><button onclick="sel=addDays(sel,-1);render()">روز قبل</button><button onclick="sel=addDays(sel,1);render()">روز بعد</button></div><h3>${showDate(sel)}</h3><div class="grid dash"><div class="c3">${kpi('تحقق روز',m.comp+'٪',`${m.d} از ${m.tot}`,m.comp)}</div><div class="c3">${kpi('باقی‌مانده',m.todo,'فعالیت فعال',m.tot?m.todo/m.tot*100:0)}</div><div class="c3">${kpi('عقب‌افتاده',m.l,'برای این روز',m.tot?m.l/m.tot*100:0)}</div><div class="c3">${kpi('میانگین پیشرفت',m.avg+'٪','بر اساس درصدها',m.avg)}</div></div></section><section class="card">${rowTitle('تمرکز اصلی روز و ۳ کار مهم','<button id="saveDay" class="primary">ذخیره تمرکز</button>')}<div class="two"><label>تمرکز اصلی<textarea id="focus">${esc(p.focus)}</textarea></label><div class="top3"><label>کار مهم ۱<input class="top" value="${esc(p.top3?.[0]||'')}"></label><label>کار مهم ۲<input class="top" value="${esc(p.top3?.[1]||'')}"></label><label>کار مهم ۳<input class="top" value="${esc(p.top3?.[2]||'')}"></label></div></div></section><section class="card">${rowTitle('نمای روزانه شبیه Google Calendar',`<button class="primary" onclick="openDlg(null,'${sel}')">+ افزودن فعالیت</button>`)}${dayTimeline(sel,ts)}</section><section class="card">${rowTitle('لیست فعالیت‌های روز')}${taskList(ts)}</section>`;$('#goDay').onclick=()=>{let v=jDate($('#dayInp').value);if(!v)return alert('تاریخ معتبر ۱۴۰۵ وارد کنید.');sel=v;mon=v.slice(0,7);wstart=week(v).start;render()};$('#saveDay').onclick=()=>{S.daily[sel]={focus:$('#focus').value.trim(),top3:$$('.top').map(x=>x.value.trim())};save();render()}}
function dayTimeline(d,ts){let uns=ts.filter(t=>!t.start),hours=Array.from({length:24},(_,h)=>h);return`${uns.length?`<div class="unscheduled"><b>بدون ساعت:</b>${uns.map(t=>`<button onclick="openDlg(S.tasks.find(x=>x.id==='${t.id}'))">${esc(t.title)}</button>`).join('')}</div>`:''}<div class="dayTimeline">${hours.map(h=>{let hs=pad(h)+':00',he=h===23?'23:59':pad(h+1)+':00',slot=ts.filter(t=>{let st=t.start||'';return st&&+st.slice(0,2)===h});return`<div class="timeSlot"><div class="timeLabel">${fa(hs)}</div><div class="timeBody" onclick="openAtHour(${h})"><span class="slotHint">${fa(hs)} تا ${fa(he)}</span>${slot.map(t=>`<article class="event ${done(t)?'done':''}" onclick="event.stopPropagation();openDlg(S.tasks.find(x=>x.id==='${t.id}'))"><b>${esc(t.title)}</b><small>${esc(t.start||'')} ${t.end?'تا '+esc(t.end):''} · ${esc(t.priority)}</small></article>`).join('')}</div></div>`}).join('')}</div>`}
function openAtHour(h){openDlg(null,sel);$('#start').value=pad(h)+':00';$('#end').value=h===23?'23:59':pad(h+1)+':00'}
function weekly(){let wr={start:wstart,end:addDays(wstart,6)},ds=dates(wr.start,wr.end),ts=inRange(wr.start,wr.end),m=met(ts),pl=S.weekly[wstart]||{focus:'',goals:['','',''],review:''};$('#app').innerHTML=`<section class="card"><div class="toolbar"><label>تاریخ داخل هفته<input id="weekInp" value="${sel}"></label><button id="goWeek" class="primary">نمایش</button><button onclick="wstart=addDays(wstart,-7);sel=wstart;render()">هفته قبل</button><button onclick="wstart=addDays(wstart,7);sel=wstart;render()">هفته بعد</button></div><h3>هفته ${fa(wr.start)} تا ${fa(wr.end)}</h3><div class="grid dash"><div class="c3">${kpi('تحقق هفته',m.comp+'٪',`${m.d} از ${m.tot}`,m.comp)}</div><div class="c3">${kpi('باقی‌مانده',m.todo,'فعالیت فعال',m.tot?m.todo/m.tot*100:0)}</div><div class="c3">${kpi('عقب‌افتاده',m.l,'نیازمند پیگیری',m.tot?m.l/m.tot*100:0)}</div><div class="c3">${kpi('میانگین پیشرفت',m.avg+'٪','بر اساس درصدها',m.avg)}</div></div></section><section class="card">${rowTitle('تمرکز و اهداف هفتگی','<button id="saveWeek" class="primary">ذخیره هفته</button>')}<div class="two"><label>تمرکز هفته<textarea id="wf">${esc(pl.focus)}</textarea></label><div class="top3"><label>هدف ۱<input class="wg" value="${esc(pl.goals?.[0]||'')}"></label><label>هدف ۲<input class="wg" value="${esc(pl.goals?.[1]||'')}"></label><label>هدف ۳<input class="wg" value="${esc(pl.goals?.[2]||'')}"></label></div></div><label style="margin-top:12px">مرور پایان هفته<textarea id="wrv">${esc(pl.review)}</textarea></label></section><section class="card">${rowTitle('برد هفتگی',`<button class="primary" onclick="openDlg(null,'${sel}')">+ افزودن فعالیت</button>`)}<div class="week">${ds.map(d=>`<div class="daycol"><b>${showDate(d).replace(String(C.year),'')}</b>${dayTasks(d).map(t=>`<div class="mini" onclick="openDlg(S.tasks.find(x=>x.id==='${t.id}'))"><b>${esc(t.title)}</b><br><span class="muted">${esc(t.start||'بدون ساعت')} · ${esc(t.priority)}</span></div>`).join('')||'<p class="muted">فعالیتی ثبت نشده</p>'}</div>`).join('')}</div></section><section class="card">${rowTitle('نمودار هفته')}<canvas id="weekChart" class="chart"></canvas></section>`;$('#goWeek').onclick=()=>{let v=jDate($('#weekInp').value);if(!v)return alert('تاریخ معتبر ۱۴۰۵ وارد کنید.');sel=v;wstart=week(v).start;render()};$('#saveWeek').onclick=()=>{S.weekly[wstart]={focus:$('#wf').value.trim(),goals:$$('.wg').map(x=>x.value.trim()),review:$('#wrv').value.trim()};save();render()};line($('#weekChart'),ds.map(d=>({label:showDate(d).split(' ')[0],value:met(dayTasks(d)).comp})))}
function goalsView(){let meta={yearly:['اهداف سالانه','افق کلان ۱۴۰۵؛ نتیجه‌های بزرگ و قابل اندازه‌گیری'],seasonal:['اهداف فصلی','تمرکز ۳ ماهه برای تبدیل هدف سالانه به پروژه اجرایی'],monthly:['اهداف ماهانه','هدف‌های کوتاه‌تر با خروجی مشخص تا پایان ماه'],edge:['حاشیه برتری','کارهای بسیار مهمی که تفاوت واقعی ایجاد می‌کنند']};$('#app').innerHTML=`<section class="card">${rowTitle('اهداف و سیستم پیشرفت','<span class="muted">پیشرفت هر هدف بر اساس تکمیل گام‌ها محاسبه می‌شود</span>')}<p class="muted">برای هر هدف، عنوان، چرایی، شاخص سنجش، نتیجه مطلوب، مهلت و گام‌های اجرایی تعریف کن. هر گام که تکمیل شود، نوار پیشرفت هدف به‌صورت خودکار جلو می‌رود.</p></section>${Object.keys(meta).map(k=>goalSection(k,meta[k][0],meta[k][1])).join('')}`}
function goalSection(k,title,sub){let arr=S.goals[k]||[];return`<section class="card goalSection"><div class="goalHead"><div><h3>${title}</h3><p class="muted">${sub}</p></div><button class="primary" onclick="goalAdd('${k}')">+ هدف جدید</button></div>${arr.length?`<div class="goalGrid">${arr.map(g=>goalCard(k,g)).join('')}</div>`:'<div class="empty">هنوز موردی ثبت نشده است.</div>'}</section>`}
function goalCard(k,g){let p=goalProgress(g);return`<article class="goalCard"><div class="goalTop"><input value="${esc(g.title||'')}" placeholder="عنوان هدف" onchange="goalSet('${k}','${g.id}','title',this.value)"><button class="danger" onclick="goalDel('${k}','${g.id}')">حذف</button></div><div class="goalMini"><label>چرایی<textarea onchange="goalSet('${k}','${g.id}','why',this.value)">${esc(g.why||'')}</textarea></label><label>شاخص سنجش<input value="${esc(g.metric||'')}" onchange="goalSet('${k}','${g.id}','metric',this.value)"></label><label>نتیجه مطلوب<input value="${esc(g.target||'')}" onchange="goalSet('${k}','${g.id}','target',this.value)"></label><label>مهلت<input value="${esc(g.due||'')}" placeholder="مثلاً 1405-06-31" onchange="goalSet('${k}','${g.id}','due',this.value)"></label></div><div class="progressBox"><b>${fa(p)}٪</b><div class="bar"><i style="width:${p}%"></i></div></div><div class="steps">${(g.steps||[]).map(s=>`<label class="checkrow"><input type="checkbox" ${s.done?'checked':''} onchange="goalToggleStep('${k}','${g.id}','${s.id}')"><span>${esc(s.title)}</span><button type="button" class="danger" onclick="event.preventDefault();goalDelStep('${k}','${g.id}','${s.id}')">×</button></label>`).join('')||'<p class="muted">گامی تعریف نشده است.</p>'}</div><div class="inlineAdd"><input id="step_${g.id}" placeholder="گام بعدی هدف"><button onclick="goalAddStep('${k}','${g.id}')">+ گام</button></div></article>`}
function goalAdd(k){S.goals[k].unshift({id:id(),title:'',why:'',metric:'',target:'',due:'',steps:[],createdAt:new Date().toISOString()});save();render()}function goalFind(k,gid){return(S.goals[k]||[]).find(g=>g.id===gid)}function goalSet(k,gid,f,v){let g=goalFind(k,gid);if(!g)return;g[f]=v;g.updatedAt=new Date().toISOString();save()}function goalDel(k,gid){if(!confirm('این هدف حذف شود؟'))return;S.goals[k]=S.goals[k].filter(g=>g.id!==gid);save();render()}function goalProgress(g){let st=g.steps||[];return st.length?Math.round(st.filter(s=>s.done).length/st.length*100):0}function goalAddStep(k,gid){let g=goalFind(k,gid),inp=$('#step_'+gid);if(!g||!inp||!inp.value.trim())return;g.steps=g.steps||[];g.steps.push({id:id(),title:inp.value.trim(),done:false});save();render()}function goalToggleStep(k,gid,sid){let g=goalFind(k,gid),s=g?.steps?.find(x=>x.id===sid);if(!s)return;s.done=!s.done;save();render()}function goalDelStep(k,gid,sid){let g=goalFind(k,gid);if(!g)return;g.steps=(g.steps||[]).filter(s=>s.id!==sid);save();render()}
function habitsView(){let d=jDate(sessionStorage.habitDay||todayJ())||todayJ();let mk=sessionStorage.habitMonth||d.slice(0,7),mr=mrange(mk);$('#app').innerHTML=`<section class="card">${rowTitle('Habit Tracker ماهانه','<span class="muted">خانه سبز یعنی انجام‌شده</span>')}<div class="toolbar"><label>ماه<select id="habitMon">${C.months.map((x,i)=>`<option value="${C.year}-${pad(i+1)}" ${mk.endsWith(pad(i+1))?'selected':''}>${x}</option>`).join('')}</select></label><label>روز چک‌لیست<input id="habitDay" value="${d}"></label><button id="habitGo" class="primary">نمایش</button></div></section><section class="card">${rowTitle('تعریف عادت جدید')}<div class="habitAdd"><label>نام عادت<input id="habitTitle" placeholder="مثلاً ورزش، مطالعه، آب کافی"></label><label>تناوب<select id="habitFreq"><option value="daily">هر روز</option><option value="weekly">چند روز در هفته</option></select></label><label>هدف هفتگی<input id="habitTarget" type="number" min="1" max="7" value="3"></label><button id="habitAddBtn" class="primary">+ افزودن عادت</button></div></section><section class="card">${rowTitle('چک‌لیست عادت‌های روز '+fa(d))}${habitChecklist(d)}</section><section class="card">${rowTitle('نقشه حرارتی ماهانه '+C.months[+mk.slice(5)-1])}${habitMonthGrid(mk)}</section>`;$('#habitGo').onclick=()=>{let v=jDate($('#habitDay').value);if(!v)return alert('تاریخ معتبر ۱۴۰۵ وارد کنید.');sessionStorage.habitDay=v;sessionStorage.habitMonth=$('#habitMon').value;sel=v;mon=v.slice(0,7);render()};$('#habitAddBtn').onclick=()=>{let title=$('#habitTitle').value.trim();if(!title)return alert('نام عادت را وارد کن.');S.habits.items.push({id:id(),title,frequency:$('#habitFreq').value,weeklyTarget:cl(+$('#habitTarget').value||3,1,7),active:true,createdAt:new Date().toISOString()});save();render()}}
function habitChecklist(d){let hs=S.habits.items.filter(h=>h.active!==false);return hs.length?`<div class="habitChecklist">${hs.map(h=>`<label class="habitCheck"><input type="checkbox" ${habitDone(h.id,d)?'checked':''} onchange="habitToggle('${h.id}','${d}')"><span>${esc(h.title)}</span><small>${h.frequency==='daily'?'هر روز':fa(h.weeklyTarget||3)+' روز در هفته'}</small></label>`).join('')}</div>`:'<div class="empty">هنوز عادتی تعریف نشده است.</div>'}
function habitMonthGrid(mk){let hs=S.habits.items.filter(h=>h.active!==false),r=mrange(mk),ds=dates(r.start,r.end);if(!hs.length)return'<div class="empty">برای مشاهده نقشه حرارتی، ابتدا عادت تعریف کن.</div>';return`<div class="habitMatrix">${hs.map(h=>{let p=habitProgress(h,ds);return`<div class="habitRow"><div class="habitName"><b>${esc(h.title)}</b><span>${fa(p)}٪</span><div class="bar"><i style="width:${p}%"></i></div><button class="danger" onclick="habitDelete('${h.id}')">حذف</button></div><div class="habitDays">${ds.map(d=>`<button class="habitCell ${habitDone(h.id,d)?'hDone':''}" onclick="habitToggle('${h.id}','${d}')" title="${d}">${fa(par(d).jd)}</button>`).join('')}</div></div>`}).join('')}</div>`}
function habitDone(hid,d){return !!(S.habits.checks[hid]&&S.habits.checks[hid][d])}function habitToggle(hid,d){S.habits.checks[hid]=S.habits.checks[hid]||{};S.habits.checks[hid][d]=!S.habits.checks[hid][d];save();render()}function habitProgress(h,ds){let done=ds.filter(d=>habitDone(h.id,d)).length,expected=h.frequency==='daily'?ds.length:Math.ceil(ds.length/7)*cl(+h.weeklyTarget||3,1,7);return Math.min(100,expected?Math.round(done/expected*100):0)}function habitDelete(hid){if(!confirm('این عادت حذف شود؟'))return;S.habits.items=S.habits.items.filter(h=>h.id!==hid);delete S.habits.checks[hid];save();render()}
function weekPerf(){let out=[];let st=week(todayJ()).start;for(let i=7;i>=0;i--){let s=addDays(st,-7*i),e=addDays(s,6);out.push({label:fa(par(s).jm+'/'+par(s).jd),value:met(inRange(s,e)).comp})}return out}function quarterPerf(){let q=[['بهار',1,3],['تابستان',4,6],['پاییز',7,9],['زمستان',10,12]];return q.map(([label,a,b])=>{let start=fmt(C.year,a,1),end=fmt(C.year,b,ml(C.year,b));return{label,value:met(inRange(start,end)).comp}})}
function dough(c,o){let e=Object.entries(o).filter(a=>+a[1]>0),[x,w,h]=setup(c);if(!e.length)return nodata(x,w,h);let total=e.reduce((s,a)=>s+ +a[1],0),defaultCols=['#74b47b','#aad8ae','#2f7a43','#dcefdc','#e7a83d','#88b99a'],prioCols={'بالا':'#dc2626','متوسط':'#facc15','پایین':'#2563eb'},cx=w*.35,cy=h*.52,r=Math.min(w,h)*.28,st=-Math.PI/2;e.forEach((a,i)=>{let an=+a[1]/total*Math.PI*2;x.beginPath();x.moveTo(cx,cy);x.arc(cx,cy,r,st,st+an);x.closePath();x.fillStyle=prioCols[a[0]]||defaultCols[i%defaultCols.length];x.fill();st+=an});x.globalCompositeOperation='destination-out';x.beginPath();x.arc(cx,cy,r*.58,0,Math.PI*2);x.fill();x.globalCompositeOperation='source-over';x.fillStyle='#15231a';x.font='700 18px Tahoma';x.textAlign='center';x.fillText(fa(total),cx,cy+6);x.textAlign='right';x.font='12px Tahoma';e.forEach((a,i)=>{let y=38+i*27;x.fillStyle=prioCols[a[0]]||defaultCols[i%defaultCols.length];x.fillRect(w-24,y-10,12,12);x.fillStyle='#15231a';x.fillText(`${a[0]}: ${fa(a[1])}`,w-32,y)})}
window.inboxToTask=inboxToTask;window.delInbox=delInbox;window.openAtHour=openAtHour;window.goalAdd=goalAdd;window.goalSet=goalSet;window.goalDel=goalDel;window.goalAddStep=goalAddStep;window.goalToggleStep=goalToggleStep;window.goalDelStep=goalDelStep;window.habitToggle=habitToggle;window.habitDelete=habitDelete;window.render=render;migratePlannerV4();

// ===== Cloud sync layer: Supabase Auth + PostgreSQL =====
const SUPABASE_STATE_TABLE='planner_states';
let cloud={enabled:false,configured:false,ready:false,user:null,client:null,saveTimer:null,applying:false,status:'لوکال'};
function cloudHasConfig(){let c=window.PLANNER_SUPABASE_CONFIG;return !!(c&&c.url&&c.anonKey&&!String(c.url).includes('PASTE')&&!String(c.anonKey).includes('PASTE'))}
function cloudInit(){cloudBuildPanel();cloud.configured=cloudHasConfig();if(!cloud.configured){cloud.status='لوکال؛ supabase-config.js هنوز تنظیم نشده است.';cloudPaint();return}if(!window.supabase||!window.supabase.createClient){cloud.status='کتابخانه Supabase بارگذاری نشد؛ فعلاً حالت لوکال فعال است.';cloudPaint();return}try{let cfg=window.PLANNER_SUPABASE_CONFIG;cloud.client=window.supabase.createClient(cfg.url,cfg.anonKey,{auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:false}});cloud.enabled=true;cloud.client.auth.onAuthStateChange((_event,session)=>cloudOnAuth(session?.user||null));cloud.client.auth.getSession().then(({data})=>cloudOnAuth(data?.session?.user||null)).catch(()=>{});cloud.status='آماده ورود ابری';cloudPaint()}catch(e){cloud.status='خطا در تنظیم Supabase: '+(e.message||e);cloudPaint()}}
function cloudBuildPanel(){let btn=$('#cloudLoginBtn'),dlg=$('#authDialog');if(btn)btn.onclick=()=>{cloudPaint();dlg.showModal()};if($('#closeAuth'))$('#closeAuth').onclick=()=>dlg.close();if($('#authForm'))$('#authForm').onsubmit=e=>{e.preventDefault();cloudSignIn()};if($('#signUpBtn'))$('#signUpBtn').onclick=()=>cloudSignUp();if($('#signOutBtn'))$('#signOutBtn').onclick=()=>cloudSignOut();if($('#forceCloudBtn'))$('#forceCloudBtn').onclick=()=>cloudSaveNow(true);let aside=document.querySelector('aside');if(aside&&!$('#cloudPanel')){let box=document.createElement('section');box.id='cloudPanel';box.className='cloudPanel';box.innerHTML='<b>همگام‌سازی ابری</b><div id="cloudStatus" class="cloudStatus">در حال بررسی...</div><button id="cloudPanelBtn" type="button">ورود / تنظیم حساب</button><small>داده‌ها روی همین دستگاه هم ذخیره می‌شوند و پس از ورود با Supabase همگام می‌شوند.</small>';let note=aside.querySelector('.note');aside.insertBefore(box,note);box.querySelector('#cloudPanelBtn').onclick=()=>{cloudPaint();dlg.showModal()}}}
function cloudMsg(t,bad=false){let m=$('#authMsg');if(m){m.textContent=t||'';m.classList.toggle('bad',!!bad)}}
function cloudPaint(){let txt=cloud.user?('متصل: '+(cloud.user.email||cloud.user.id)):(cloud.configured?'وارد نشده‌اید':'فقط لوکال');let extra=cloud.status?(' — '+cloud.status):'';let st=$('#cloudStatus');if(st)st.textContent=txt+extra;let top=$('#cloudLoginBtn');if(top)top.textContent=cloud.user?'حساب ابری':'ورود ابری';let out=$('#signOutBtn');if(out)out.classList.toggle('hide',!cloud.user);let force=$('#forceCloudBtn');if(force)force.classList.toggle('hide',!cloud.user);let em=$('#authEmail');if(em&&cloud.user?.email)em.value=cloud.user.email;let note=document.querySelector('aside .note');if(note)note.textContent=cloud.user?'اطلاعات هم روی این دستگاه و هم در Supabase ذخیره می‌شود.':'در حالت فعلی، اطلاعات لوکال ذخیره می‌شود. برای دسترسی در همه دستگاه‌ها وارد حساب ابری شو.'}
async function cloudSignIn(){if(!cloud.enabled)return cloudMsg('ابتدا supabase-config.js را با مشخصات Supabase تکمیل کن.',true);let email=$('#authEmail').value.trim(),password=$('#authPass').value;if(!email||!password)return;cloudMsg('در حال ورود...');try{let {error}=await cloud.client.auth.signInWithPassword({email,password});if(error)throw error;cloudMsg('ورود انجام شد. اطلاعات در حال همگام‌سازی است.')}catch(e){cloudMsg(cloudAuthError(e),true)}}
async function cloudSignUp(){if(!cloud.enabled)return cloudMsg('ابتدا supabase-config.js را با مشخصات Supabase تکمیل کن.',true);let email=$('#authEmail').value.trim(),password=$('#authPass').value;if(!email||!password)return;cloudMsg('در حال ساخت حساب...');try{let {error}=await cloud.client.auth.signUp({email,password});if(error)throw error;cloudMsg('حساب ساخته شد. اگر تأیید ایمیل را خاموش کرده باشی، همگام‌سازی همین حالا شروع می‌شود.')}catch(e){cloudMsg(cloudAuthError(e),true)}}
async function cloudSignOut(){try{await cloud.client.auth.signOut();cloud.ready=false;cloud.user=null;cloud.status='از حساب خارج شدی؛ برنامه لوکال کار می‌کند.';cloudPaint();cloudMsg('از حساب ابری خارج شدی.')}catch(e){cloudMsg(cloudAuthError(e),true)}}
function cloudAuthError(e){let c=e?.code||'',m=e?.message||String(e||'');if(m.includes('Invalid login credentials'))return'ایمیل یا رمز عبور اشتباه است.';if(m.includes('Email not confirmed'))return'ایمیل هنوز تأیید نشده است. در Supabase گزینه Confirm email را خاموش کن یا ایمیل را تأیید کن.';if(m.includes('User already registered'))return'با این ایمیل قبلاً حساب ساخته شده است.';if(m.includes('Password'))return'رمز عبور باید حداقل ۶ کاراکتر باشد.';if(c==='23503')return'کاربر در Supabase ساخته نشده یا ورود انجام نشده است.';return m||'خطای نامشخص در ورود ابری.'}
async function cloudOnAuth(u){cloud.user=u||null;cloud.ready=false;if(!u){cloud.status='وارد نشده‌اید';cloudPaint();return}cloud.status='در حال دریافت اطلاعات از Supabase...';cloudPaint();await cloudPullNow()}
async function cloudPullNow(){if(!cloud.user||!cloud.client)return;try{let {data,error}=await cloud.client.from(SUPABASE_STATE_TABLE).select('state,updated_at,local_updated_at').eq('user_id',cloud.user.id).maybeSingle();if(error)throw error;cloud.ready=true;if(!data||!data.state){cloud.status='ابر خالی بود؛ اطلاعات لوکال روی Supabase ذخیره شد.';cloudPaint();await cloudSaveNow(true);return}let state=data.state;if(state&&Array.isArray(state.tasks)){let incoming=JSON.stringify(state);let local=JSON.stringify(S);if(incoming!==local){cloud.applying=true;S=Object.assign(seed(),state);localStorage.setItem(K,JSON.stringify(S));window.S=S;cloud.applying=false;cloud.status='همگام‌سازی شد';cloudPaint();render()}else{cloud.status='اطلاعات لوکال و ابری یکسان است.';cloudPaint()}}else{cloud.status='داده ابری معتبر نبود؛ اطلاعات لوکال حفظ شد.';cloudPaint()}}catch(e){cloud.status='خطای دریافت Supabase: '+(e.message||e);cloudPaint();cloudMsg('خطای دریافت از Supabase: '+(e.message||e),true)}}
function cloudScheduleSave(force=false){if(cloud.applying)return;if(!cloud.user||!cloud.client||(!cloud.ready&&!force))return;clearTimeout(cloud.saveTimer);cloud.saveTimer=setTimeout(()=>cloudSaveNow(false),force?50:900)}
async function cloudSaveNow(force=false){if(!cloud.user||!cloud.client||cloud.applying)return;try{let clean=JSON.parse(JSON.stringify(S));cloud.status='در حال ذخیره ابری...';cloudPaint();let payload={user_id:cloud.user.id,state:clean,local_updated_at:clean.updatedAt||new Date().toISOString(),schema:'planner-1405-supabase-v5'};let {error}=await cloud.client.from(SUPABASE_STATE_TABLE).upsert(payload,{onConflict:'user_id'});if(error)throw error;cloud.ready=true;cloud.status='ذخیره ابری انجام شد';cloudPaint();if(force)cloudMsg('اطلاعات لوکال با Supabase همگام شد.')}catch(e){cloud.status='ذخیره ابری ناموفق: '+(e.message||e);cloudPaint();cloudMsg('ذخیره ابری ناموفق: '+(e.message||e),true)}}
window.cloudSaveNow=cloudSaveNow;
window.cloudPullNow=cloudPullNow;


// ===== Planner v5 fixes: spanning daily calendar, compact goals, safe date picker =====
function timeMin(v){let m=String(v||'').match(/^(\d{1,2}):(\d{2})/);if(!m)return null;return cl(+m[1]*60+(+m[2]),0,1439)}
function jToISO(s){let jd=jDate(s);if(!jd)return'';let d=jToDate(jd);return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`}
function isoToJ(s){if(!s)return'';let d=new Date(String(s)+'T00:00:00');if(isNaN(d))return'';let j=dateToJ(d);return j.startsWith(String(C.year))?j:''}
function dayTimeline(d,ts){
  let uns=ts.filter(t=>!t.start), timed=ts.filter(t=>t.start).sort((a,b)=>(a.start||'').localeCompare(b.start||''));
  let labels=Array.from({length:24},(_,h)=>`<div class="timelineLabel" style="top:${h*60}px">${fa(pad(h)+':00')}</div>`).join('');
  let lines=Array.from({length:25},(_,h)=>`<div class="timelineLine" style="top:${h*60}px"></div>`).join('');
  let events=timed.map((t,i)=>{
    let st=timeMin(t.start), en=timeMin(t.end); if(st===null)st=0; if(en===null||en<=st)en=Math.min(1440,st+60); let height=Math.max(38,en-st), top=st;
    let cls=done(t)?'done':late(t)?'late':'';
    return `<article class="calendarEvent ${cls}" style="top:${top}px;height:${height}px;right:${(i%3)*2}%;left:${(i%3)*2}%;" onclick="event.stopPropagation();openDlg(S.tasks.find(x=>x.id==='${t.id}'))"><b>${esc(t.title)}</b><small>${esc(t.start||'')} ${t.end?'تا '+esc(t.end):''} · ${esc(t.priority||'')}</small></article>`
  }).join('');
  return `${uns.length?`<div class="unscheduled"><b>بدون ساعت:</b>${uns.map(t=>`<button onclick="openDlg(S.tasks.find(x=>x.id==='${t.id}'))">${esc(t.title)}</button>`).join('')}</div>`:''}<div class="timelineHelp muted">برای ثبت سریع، روی بازه خالی کلیک کن. فعالیت‌های دارای ساعت شروع و پایان، کل بازه را رنگی می‌کنند.</div><div class="dayTimelineV5"><div class="timelineLabels">${labels}</div><div class="timelineCanvas" onclick="timelineClick(event)">${lines}${events}</div></div>`
}
function timelineClick(e){let c=e.currentTarget.getBoundingClientRect(),y=cl(e.clientY-c.top,0,1439),h=Math.floor(y/60),m=y%60<30?'00':'30';openDlg(null,sel);$('#start').value=pad(h)+':'+m;let endM=Math.min(1439,h*60+(m==='30'?90:60));$('#end').value=pad(Math.floor(endM/60))+':'+pad(endM%60)}
function openAtHour(h){openDlg(null,sel);$('#start').value=pad(h)+':00';$('#end').value=h===23?'23:59':pad(h+1)+':00'}
function goalsView(){let meta={yearly:['اهداف سالانه','افق کلان ۱۴۰۵؛ نتیجه‌های بزرگ و قابل اندازه‌گیری'],seasonal:['اهداف فصلی','تمرکز ۳ ماهه برای تبدیل هدف سالانه به پروژه اجرایی'],monthly:['اهداف ماهانه','هدف‌های کوتاه‌تر با خروجی مشخص تا پایان ماه'],edge:['حاشیه برتری','کارهای بسیار مهمی که تفاوت واقعی ایجاد می‌کنند']};$('#app').innerHTML=`<section class="card">${rowTitle('اهداف و حاشیه برتری','<span class="muted">کارت‌ها جمع‌شونده هستند؛ برای جزئیات روی هر هدف بزن</span>')}<p class="muted">در این نسخه هر هدف خلاصه و فشرده نمایش داده می‌شود: عنوان، چرایی، نتیجه مطلوب، مهلت تقویمی و گام‌ها. پیشرفت هدف فقط با تکمیل گام‌ها محاسبه می‌شود و به‌صورت نوار بصری نمایش داده می‌شود.</p></section>${Object.keys(meta).map(k=>goalSection(k,meta[k][0],meta[k][1])).join('')}`}
function goalSection(k,title,sub){let arr=S.goals[k]||[];return`<section class="card goalSection"><div class="goalHead"><div><h3>${title}</h3><p class="muted">${sub}</p></div><button class="primary" onclick="goalAdd('${k}')">+ هدف جدید</button></div>${arr.length?`<div class="goalList">${arr.map(g=>goalCard(k,g)).join('')}</div>`:'<div class="empty">هنوز موردی ثبت نشده است.</div>'}</section>`}
function goalCard(k,g){let p=goalProgress(g),doneSteps=(g.steps||[]).filter(s=>s.done).length,totalSteps=(g.steps||[]).length;return`<details class="goalCard goalCompact"><summary><div class="goalSummary"><input class="goalTitleInput" value="${esc(g.title||'')}" placeholder="عنوان هدف" onclick="event.stopPropagation()" onchange="goalSet('${k}','${g.id}','title',this.value)"><div class="goalSummaryBar"><span>${fa(p)}٪</span><div class="bar goalBar"><i style="width:${p}%"></i></div><small>${fa(doneSteps)} از ${fa(totalSteps)} گام</small></div><button class="danger" onclick="event.preventDefault();event.stopPropagation();goalDel('${k}','${g.id}')">حذف</button></div></summary><div class="goalDetails"><div class="goalMini goalMiniV5"><label>چرایی<textarea onchange="goalSet('${k}','${g.id}','why',this.value)">${esc(g.why||'')}</textarea></label><label>نتیجه مطلوب<textarea onchange="goalSet('${k}','${g.id}','target',this.value)">${esc(g.target||'')}</textarea></label><label>مهلت<input type="date" value="${esc(jToISO(g.due||''))}" onchange="goalDueISO('${k}','${g.id}',this.value)"><small class="muted">مهلت شمسی: ${esc(g.due||'ثبت نشده')}</small></label></div><div class="steps">${(g.steps||[]).map(s=>`<label class="checkrow"><input type="checkbox" ${s.done?'checked':''} onchange="goalToggleStep('${k}','${g.id}','${s.id}')"><span>${esc(s.title)}</span><button type="button" class="danger" onclick="event.preventDefault();goalDelStep('${k}','${g.id}','${s.id}')">×</button></label>`).join('')||'<p class="muted">گامی تعریف نشده است.</p>'}</div><div class="inlineAdd"><input id="step_${g.id}" placeholder="گام بعدی هدف"><button onclick="goalAddStep('${k}','${g.id}')">+ گام</button></div></div></details>`}
function goalDueISO(k,gid,iso){let g=goalFind(k,gid);if(!g)return;let jd=isoToJ(iso);if(!jd&&iso)return alert('مهلت انتخابی باید در سال ۱۴۰۵ باشد.');g.due=jd;g.updatedAt=new Date().toISOString();save();render()}
window.timelineClick=timelineClick;window.goalDueISO=goalDueISO;


// ===== Planner v6 cloud reliability: timeout, retry, connection test, no infinite loading =====
const CLOUD_LOGIN_TIMEOUT_MS = 16000;
const CLOUD_DATA_TIMEOUT_MS = 22000;
function cloudWithTimeout(promise, ms, label){
  return Promise.race([
    promise,
    new Promise((_, reject)=>setTimeout(()=>{
      let e = new Error(label || 'درخواست بیش از حد طول کشید.');
      e.code = 'PLANNER_TIMEOUT';
      reject(e);
    }, ms))
  ]);
}
function cloudSetBusy(on, text){
  cloud.busy = !!on;
  ['signInBtn','signUpBtn','forceCloudBtn','signOutBtn','cloudTestBtn'].forEach(id=>{
    let b = document.getElementById(id);
    if(b) b.disabled = !!on;
  });
  if(text) cloudMsg(text);
}
function cloudResetBusy(){
  cloud.busy = false;
  ['signInBtn','signUpBtn','forceCloudBtn','signOutBtn','cloudTestBtn'].forEach(id=>{
    let b = document.getElementById(id);
    if(b) b.disabled = false;
  });
}
function cloudBuildPanel(){
  let btn=$('#cloudLoginBtn'),dlg=$('#authDialog');
  if(btn)btn.onclick=()=>{cloudPaint();dlg.showModal()};
  if($('#closeAuth'))$('#closeAuth').onclick=()=>{cloudResetBusy();dlg.close()};
  if($('#authForm'))$('#authForm').onsubmit=e=>{e.preventDefault();cloudSignIn()};
  if($('#signUpBtn'))$('#signUpBtn').onclick=()=>cloudSignUp();
  if($('#signOutBtn'))$('#signOutBtn').onclick=()=>cloudSignOut();
  if($('#forceCloudBtn'))$('#forceCloudBtn').onclick=()=>cloudSaveNow(true);
  let actions=document.querySelector('#authDialog .authActions');
  if(actions && !$('#cloudTestBtn')){
    let b=document.createElement('button');
    b.id='cloudTestBtn';
    b.type='button';
    b.textContent='تست اتصال';
    b.onclick=cloudTestConnection;
    actions.appendChild(b);
  }
  let aside=document.querySelector('aside');
  if(aside&&!$('#cloudPanel')){
    let box=document.createElement('section');
    box.id='cloudPanel';
    box.className='cloudPanel';
    box.innerHTML='<b>همگام‌سازی ابری</b><div id="cloudStatus" class="cloudStatus">در حال بررسی...</div><button id="cloudPanelBtn" type="button">ورود / تنظیم حساب</button><small>داده‌ها روی همین دستگاه هم ذخیره می‌شوند و پس از ورود با Supabase همگام می‌شوند.</small>';
    let note=aside.querySelector('.note');
    aside.insertBefore(box,note);
    box.querySelector('#cloudPanelBtn').onclick=()=>{cloudPaint();dlg.showModal()}
  }
}
function cloudAuthError(e){
  let c=e?.code||'',m=e?.message||String(e||'');
  if(c==='PLANNER_TIMEOUT'||m.includes('PLANNER_TIMEOUT')||m.includes('بیش از حد طول'))return 'اتصال به Supabase بیش از حد طول کشید. برنامه لوکال سالم است؛ یک‌بار تست اتصال را بزن یا با اینترنت/VPN دیگر امتحان کن.';
  if(m.includes('Failed to fetch')||m.includes('NetworkError')||m.includes('Load failed')||m.includes('fetch'))return 'ارتباط با Supabase برقرار نشد. معمولاً مشکل از فیلتر/VPN/DNS یا قطع دسترسی به supabase.co است.';
  if(m.includes('Invalid login credentials'))return'ایمیل یا رمز عبور اشتباه است.';
  if(m.includes('Email not confirmed'))return'ایمیل هنوز تأیید نشده است. در Supabase گزینه Confirm email را خاموش کن یا ایمیل را تأیید کن.';
  if(m.includes('User already registered'))return'با این ایمیل قبلاً حساب ساخته شده است.';
  if(m.includes('Password'))return'رمز عبور باید حداقل ۶ کاراکتر باشد.';
  if(c==='23503')return'کاربر در Supabase ساخته نشده یا ورود انجام نشده است.';
  return m||'خطای نامشخص در ورود ابری.'
}
async function cloudTestConnection(){
  if(!cloud.configured)return cloudMsg('supabase-config.js تنظیم نشده است.',true);
  let cfg=window.PLANNER_SUPABASE_CONFIG;
  cloudSetBusy(true,'در حال تست اتصال به Supabase...');
  try{
    let res=await cloudWithTimeout(fetch(cfg.url+'/auth/v1/settings',{cache:'no-store'}),9000,'timeout');
    if(!res.ok)throw new Error('HTTP '+res.status);
    cloudMsg('اتصال به Supabase برقرار است. حالا دوباره ورود را بزن.');
    cloud.status='اتصال Supabase برقرار است';cloudPaint();
  }catch(e){
    cloud.status='تست اتصال ناموفق';cloudPaint();
    cloudMsg(cloudAuthError(e),true);
  }finally{cloudResetBusy()}
}
async function cloudSignIn(){
  if(cloud.busy)return;
  if(!cloud.enabled)return cloudMsg('ابتدا supabase-config.js را با مشخصات Supabase تکمیل کن.',true);
  if(!navigator.onLine)return cloudMsg('مرورگر آفلاین است. اینترنت دستگاه را بررسی کن.',true);
  let email=$('#authEmail').value.trim(),password=$('#authPass').value;
  if(!email||!password)return;
  cloudSetBusy(true,'در حال ورود... اگر بیش از ۱۵ ثانیه طول بکشد، پیام خطا نمایش داده می‌شود.');
  try{
    let {data,error}=await cloudWithTimeout(cloud.client.auth.signInWithPassword({email,password}),CLOUD_LOGIN_TIMEOUT_MS,'timeout-login');
    if(error)throw error;
    if(data?.user){cloud.user=data.user;cloud.status='ورود انجام شد؛ در حال دریافت اطلاعات...';cloudPaint()}
    cloudMsg('ورود انجام شد. همگام‌سازی شروع شد.');
  }catch(e){
    cloud.status='ورود ناموفق یا کند';cloudPaint();cloudMsg(cloudAuthError(e),true);
  }finally{cloudResetBusy()}
}
async function cloudSignUp(){
  if(cloud.busy)return;
  if(!cloud.enabled)return cloudMsg('ابتدا supabase-config.js را با مشخصات Supabase تکمیل کن.',true);
  if(!navigator.onLine)return cloudMsg('مرورگر آفلاین است. اینترنت دستگاه را بررسی کن.',true);
  let email=$('#authEmail').value.trim(),password=$('#authPass').value;
  if(!email||!password)return;
  cloudSetBusy(true,'در حال ساخت حساب...');
  try{
    let {data,error}=await cloudWithTimeout(cloud.client.auth.signUp({email,password}),CLOUD_LOGIN_TIMEOUT_MS,'timeout-signup');
    if(error)throw error;
    if(data?.user){cloud.user=data.user;cloud.status='حساب ساخته شد؛ در حال همگام‌سازی...';cloudPaint()}
    cloudMsg('حساب ساخته شد. اگر تأیید ایمیل خاموش باشد، همگام‌سازی شروع می‌شود.');
  }catch(e){
    cloud.status='ساخت حساب ناموفق یا کند';cloudPaint();cloudMsg(cloudAuthError(e),true);
  }finally{cloudResetBusy()}
}
async function cloudOnAuth(u){
  cloud.user=u||null;cloud.ready=false;
  if(!u){cloud.status='وارد نشده‌اید';cloudPaint();return}
  cloud.status='متصل شد؛ در حال دریافت اطلاعات از Supabase...';cloudPaint();
  cloudPullNow();
}
async function cloudPullNow(){
  if(!cloud.user||!cloud.client)return;
  try{
    let req=cloud.client.from(SUPABASE_STATE_TABLE).select('state,updated_at,local_updated_at').eq('user_id',cloud.user.id).maybeSingle();
    let {data,error}=await cloudWithTimeout(req,CLOUD_DATA_TIMEOUT_MS,'timeout-pull');
    if(error)throw error;
    cloud.ready=true;
    if(!data||!data.state){
      cloud.status='ابر خالی بود؛ اطلاعات لوکال روی Supabase ذخیره شد.';cloudPaint();
      await cloudSaveNow(true);return
    }
    let state=data.state;
    if(state&&Array.isArray(state.tasks)){
      let incoming=JSON.stringify(state),local=JSON.stringify(S);
      if(incoming!==local){cloud.applying=true;S=Object.assign(seed(),state);localStorage.setItem(K,JSON.stringify(S));window.S=S;cloud.applying=false;cloud.status='همگام‌سازی شد';cloudPaint();render()}
      else{cloud.status='اطلاعات لوکال و ابری یکسان است.';cloudPaint()}
    }else{cloud.status='داده ابری معتبر نبود؛ اطلاعات لوکال حفظ شد.';cloudPaint()}
  }catch(e){
    cloud.ready=false;cloud.status='دریافت ابری ناموفق؛ حالت لوکال فعال است';cloudPaint();cloudMsg('دریافت از Supabase انجام نشد: '+cloudAuthError(e),true)
  }
}
async function cloudSaveNow(force=false){
  if(!cloud.user||!cloud.client||cloud.applying)return;
  try{
    let clean=JSON.parse(JSON.stringify(S));cloud.status='در حال ذخیره ابری...';cloudPaint();
    let payload={user_id:cloud.user.id,state:clean,local_updated_at:clean.updatedAt||new Date().toISOString(),schema:'planner-1405-supabase-v6'};
    let req=cloud.client.from(SUPABASE_STATE_TABLE).upsert(payload,{onConflict:'user_id'});
    let {error}=await cloudWithTimeout(req,CLOUD_DATA_TIMEOUT_MS,'timeout-save');
    if(error)throw error;
    cloud.ready=true;cloud.status='ذخیره ابری انجام شد';cloudPaint();if(force)cloudMsg('اطلاعات لوکال با Supabase همگام شد.')
  }catch(e){cloud.status='ذخیره ابری ناموفق؛ داده‌ها لوکال حفظ شد';cloudPaint();cloudMsg('ذخیره ابری انجام نشد: '+cloudAuthError(e),true)}
}
window.cloudSaveNow=cloudSaveNow;window.cloudPullNow=cloudPullNow;window.cloudTestConnection=cloudTestConnection;


init();
